import psycopg2
from getpass import getpass

def create_extension(conn, extension_name):
    try:
        cur = conn.cursor()
        cur.execute("CREATE EXTENSION IF NOT EXISTS {}".format(extension_name))
        conn.commit()
        print(f"Extension {extension_name} created successfully.")
    except Exception as e:
        print(f"Error creating extension: {e}")

def enable_extension(conn, extension_name):
    try:
        cur = conn.cursor()
        cur.execute("ALTER EXTENSION {} ENABLE;".format(extension_name))
        conn.commit()
        print(f"Extension {extension_name} enabled successfully.")
    except Exception as e:
        print(f"Error enabling extension: {e}")

def main():
    username = input("Enter database username: ")
    password = getpass("Enter database password: ")
    host = input("Enter database host (default=localhost): ") or "localhost"
    port = input("Enter database port (default=5432): ") or 5432
    db_name = input("Enter database name: ")

    conn = psycopg2.connect(
        dbname=db_name,
        user=username,
        password=password,
        host=host,
        port=port
    )

    while True:
        print("\n1. Create extension")
        print("2. Enable extension")
        print("3. Exit")
        choice = input("Enter your choice: ")

        if choice == "1":
            extension_name = input("Enter extension name (e.g., plpythonu): ")
            create_extension(conn, extension_name)
        elif choice == "2":
            extension_name = input("Enter extension name to enable (e.g., plpythonu): ")
            enable_extension(conn, extension_name)
        elif choice == "3":
            break
        else:
            print("Invalid choice. Please try again.")

    conn.close()

if __name__ == "__main__":
    main()